import React from "react";
import './Footer.css';

function Footer() {
    return (
        <div className="footer">
            <h2>Thanks for visiting!</h2>
            <div className="subtitle">Get in touch on <a href="https://linkedin.com/in/korevillo/">LinkedIn</a></div>
            <p>© 2024 Katrina Orevillo</p>
        </div>
    );
}

export default Footer;
